diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..289611d7dbb6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3150,6 +3150,41 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // Handle the pattern:
+  // %s1 = select C1, a, b
+  // %and = select C1, C2, false
+  // %s2 = select %and, c, %s1
+  // ->
+  // %s1 = select C2, c, a
+  // %s2 = select C1, %s1, b
+  //
+  // This transforms: select (select C1, C2, false), c, (select C1, a, b)
+  // into: select C1, (select C2, c, a), b
+  if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    Value *C1 = CondSI->getCondition();
+    Value *C2 = CondSI->getTrueValue();
+    // Match pattern: select C1, C2, false
+    if (match(CondSI->getFalseValue(), m_Zero())) {
+      // C2 should be i1 type
+      if (C2->getType()->isIntOrIntVectorTy(1)) {
+        // FalseVal should be a select with condition C1
+        if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+          if (FalseSI->getCondition() == C1 &&
+              FalseSI->getCondition()->getType() == CondVal->getType()) {
+            if (FalseSI->hasOneUse()) {
+              Value *A = FalseSI->getTrueValue();
+              Value *B = FalseSI->getFalseValue();
+              // Create: select C2, TrueVal, A
+              Value *InnerSel = Builder.CreateSelect(C2, TrueVal, A, SI.getName() + ".inner");
+              // Create: select C1, InnerSel, B
+              return SelectInst::Create(C1, InnerSel, B, SI.getName());
+            }
+          }
+        }
+      }
+    }
+  }
+
